var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"오래전 아마존 유역 원주민에게는 어떤 전설이 전해져 왔다.","JPN":"古くからアマゾン流域の先住民には、とある伝説が語り継がれてきた。","ENG":"Long ago, a legend was passed down among the indigenous people of the Amazon basin.","TWN":"很久以前，在亞馬遜流域的原住民之間，流傳著一則傳說。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"그것은 어느 종말에 관한 예언.","JPN":"それは終末に関する予言。","ENG":"It spoke of a prophecy of the world's end.","TWN":"那是關於某個末日的預言。  "},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"찬란하게 빛나는 태양이 나무뿌리에 가려, 그 빛을 잃어버리게 될 때.","JPN":"燦々と輝く太陽が木の根に隠れ、その光を失う時。","ENG":"When the radiant sun is veiled by roots, its light fading away...","TWN":"當璀璨耀眼的陽光被樹根遮蔽而失去光芒之時，"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"하늘이 갈라지며 땅과 구름이 맞닿는 곳, 어딘가 황금의 도시가 모습을 드러내고.","JPN":"天が切り裂かれ、地と雲が交わる場所、そのどこかに黄金の都市が姿を現し、","ENG":"The heavens will split open, and where earth and cloud meet, a golden city will appear.","TWN":"天空將會裂開，在大地與雲彩交會的地方，黃金城將現身。  "},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"narration","speaker":null,"text":{"KOREA":"그곳, 황금향이 남긴 유산이 수많은 이들을 구하게 될 것이라는 이야기.","JPN":"かの地、黄金郷が残した遺産が多くの者を救うであろうという伝説だ。","ENG":"There, the Golden Vale's Legacy will save countless lives.","TWN":"據說，黃金城留下的寶藏，將拯救無數的人。  "},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"narration","speaker":null,"text":{"KOREA":"노스트라다무스의 지구 종말론, 마야족의 달력설, 시빌라의 예언서…….","JPN":"ノストラダムスの人類滅亡論、マヤ族の暦にまつわる話、シビュラの書……","ENG":"Nostradamus' doomsday prophecies, the Mayan calendar, the Sibyl's oracles...","TWN":"諾斯特拉達穆斯的地球末日論、馬雅曆法的末日說、西比拉的預言書……  "},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"narration","speaker":null,"text":{"KOREA":"세계 종말에 관한 예언은 어느 시대에나 존재했고 또한 부질없이 사라졌으니.","JPN":"世界終末に関する予言はどの時代にも存在し、その度に虚しく消えていった。","ENG":"Every age has had its own visions of the world's end, and every one of them faded into nothing.","TWN":"關於世界末日的預言，在任何時代都曾存在，最後也都悄然消逝。  "},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"narration","speaker":null,"text":{"KOREA":"황금향에 관한 전설 또한 특별히 그보다 낫다고 말할 수는 없었다.","JPN":"黄金郷の伝説もまた然り。それらの予言よりもましだとは言えなかった。","ENG":"The legend of the Golden Vale was no different or better than the rest.","TWN":"黃金城的傳說，也無法說比這些預言更加可信。  "},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"narration","speaker":null,"text":{"KOREA":"늘 그렇듯, 사료는 빈약했고 현실적인 문제는 넘쳐났으니까.","JPN":"ご多分に漏れず史料は乏しく、現実的な問題は山積みだった。","ENG":"As always, the records were scarce, while real-world problems were endless.","TWN":"一如往常，史料稀少，現世問題層出不窮。  "},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"narration","speaker":null,"text":{"KOREA":"그럼에도…….","JPN":"にもかかわらず……","ENG":"And yet...","TWN":"就算是這樣……  "},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"narration","speaker":null,"text":{"KOREA":"그럼에도 나는 무언가에 홀린 듯, 계속해서 황금향을 쫓고 있었다.","JPN":"それにもかかわらず、ワシは何かに取り憑かれたように、黄金郷を追い続けていた。","ENG":"And yet, as if bewitched, I kept chasing after the Golden Vale.","TWN":"就算是這樣，我依然像是著了魔一般，不斷追尋著黃金城。  "},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"narration","speaker":null,"text":{"KOREA":"그렇게 속절없이 세월은 흐르고…….","JPN":"そうやって無情にも時は流れ……","ENG":"So the years slipped by in vain...","TWN":"歲月在不知不覺中流逝……  "},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"narration","speaker":null,"text":{"KOREA":"수많은 예언이 비웃음거리가 되어, 하나둘씩 역사의 뒤안길로 사라져갈 무렵.","JPN":"数多の予言が夢物語となり、徐々に歴史の中に埋もれていく頃。","ENG":"By the time most prophecies had become laughingstocks and faded into history...","TWN":"無數預言淪為笑柄，逐一被歷史的洪流吞沒之時，"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>관리 실패</color>가 일어나, 세계 각지에 대균열이 발생하고.","JPN":"<color=#ffd34c>管理失敗</color>により世界各地に大亀裂が発生し、","ENG":"The <color=#ffd34c>Administration Failure</color> struck, and the Grand Dimension Crevice erupted across the world.","TWN":"發生<color=#ffd34c>管理失敗</color>，世界各地出現大峽谷。  "},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"narration","speaker":null,"text":{"KOREA":"아마존 일대는 하늘이 갈라지며, 땅이 부유하기 시작했다.","JPN":"アマゾン一帯は天が切り裂かれ、地面は浮遊した。","ENG":"Here in the Amazon, the sky split apart, and the land itself began to float.","TWN":"亞馬遜一帶的天空裂開，大地開始漂浮。  "},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"narration","speaker":null,"text":{"KOREA":"그로부터 20여 년 뒤…….","JPN":"それから20年後……","ENG":"And twenty years later...","TWN":"20年後……  "},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"narration","speaker":null,"text":{"KOREA":"사람들은 구름과 땅이 맞닿은 이곳을 <color=#ffd34c>천공섬</color>이라고 불렀고.","JPN":"人々は雲と地が交わるここを<color=#ffd34c>天空島</color>と呼ぶようになり……","ENG":"People came to call this place, where cloud and earth touched, the <color=#ffd34c>floating island</color>.","TWN":"人們稱雲與地相接的這片土地為<color=#ffd34c>天空島</color>。  "},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"narration","speaker":null,"text":{"KOREA":"나는 여전히 황금향의 유산을 쫓고 있었다.","JPN":"ワシは依然として黄金郷の遺産を追いかけている。","ENG":"And I was still pursuing the Golden Vale's Legacy.","TWN":"而我，依然在追尋黃金城的寶藏。  "},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>캄파멘토</color>\\n해발 고도 약 10,000m 지점 <color=#ffd34c>태양이 떠오르는 천공섬</color>","JPN":"管理局直轄都市<color=#ffd34c>カンパメント</color>\\n標高約10,000m地点、<color=#ffd34c>太陽が昇る天空島</color>","ENG":"Administration Direct Control City, <color=#ffd34c>Campamento</color>\\nApprox. 10,000 meters above sea level, <color=#ffd34c>Dawnbreak Floating Island</color>.","TWN":"管理局直轄市<color=#ffd34c>坎帕門托</color>\\n海拔約10,000公尺處的 <color=#ffd34c>日出東方天空島</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_QM","text":{"KOREA":"침식체 토벌 확인. 에어리어 감마, 정화 작전 완료.","JPN":"侵食体の討伐を確認。エリアガンマ、浄化作戦完了。","ENG":"C.O. extermination confirmed. Area Gamma, purification op complete.","TWN":"已確認殲滅侵蝕體。伽瑪區域，淨化作戰完成。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_QM","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L36_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_QM","text":{"KOREA":"제가 자리를 비운 그새를 못 참고 또 탐험대를 소집해서 천공섬을 방문하셨더군요.","JPN":"私が留守の間、さっそく探検隊を招集して天空島を訪ねたそうですね。","ENG":"The moment I was away, you couldn't resist calling another expedition to the floating island.","TWN":"我才剛離開一下，你就又忍不住召集探險隊前往天空島是吧？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_QM","text":{"KOREA":"어디 다치신 데는 없습니까, 시니어 칸?","JPN":"お怪我はありませんか？　シニア・カン。","ENG":"You're not hurt, are you, Senior Khan?","TWN":"沒受傷吧，Senior？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"이야~ 역시 공인 카운터 제도는 편리하단 말이지~?","JPN":"いやぁ～、やはり公認カウンター制度は便利なものじゃのう。","ENG":"Heh, gotta admit. The Official Counter system is convenient, isn't it?","TWN":"哇～公認制裁者制度果然很便利呢～ "},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L41_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"1급 탐험대가 발이 묶여 쩔쩔매던 대형 침식체 무리를 호출 한 번으로 해결할 수 있다니.","JPN":"1級探検隊も太刀打ちできなかった大型侵食体の群れを、呼び出し1回で解決できるとは。","ENG":"Who would've thought a single summon could wipe out a swarm of C.O.s that even a Class 1 expedition team was helpless against?","TWN":"連一級探險隊都束手無策的一大群侵蝕體，只要一通電話就能解決！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"매번 노인네 뒤치다꺼리하느라 자네가 고생이 많아, 웨이드.","JPN":"この老いぼれのせいで、毎回手間をかけるのう、ウェイド。","ENG":"You've had a rough time cleaning up after this old man, Wade.","TWN":"每次都得幫我這個老傢伙收拾善後，真是辛苦你啦，韋德。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"칭찬은 됐습니다. 시니어를 지키는 게, 공인 카운터의 최우선 사항이니까요.","JPN":"よしてください。シニアを守ることが、公認カウンターの最優先事項なのですから。","ENG":"No need for compliments. Protecting a Senior is an Official Counter's top priority.","TWN":"這些話就免了。保護前輩，就是公認制裁者的首要任務。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"물론, 최우선 사항을 남발하는 악질 시니어가 있다는 건, 시스템의 헛점이겠지만요.","JPN":"悪質なシニアは最優先事項を悪用しまくれるという点は、システムの穴ですがね。","ENG":"Though the fact that some Seniors abuse that priority... says a lot about the system's flaws.","TWN":"不過，也因為有像你這樣濫用體制的人，才讓系統變得有漏洞吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"허허, 이거 악질이라서 미안하구만.","JPN":"ホホ、悪質ですまんのう。","ENG":"Ha ha, my apologies for being such a troublesome old man.","TWN":"哈哈，抱歉，我真糟糕。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"뭐, 회의가 따분하던 참이었으니까 이번에는 특별히 눈감아드리죠.","JPN":"ま、ちょうど退屈な会議の途中でしたし、今回は見逃してあげましょう。","ENG":"Well, the meetings were dull anyway. I'll let it slide this time.","TWN":"算了，剛好開會太無聊，這次特別睜一隻眼閉一隻眼吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"그래서? 천공섬 탐색은 어떻게 되어가고 있습니까?","JPN":"それで？　天空島探索の進捗はどういう具合ですか？","ENG":"So? How's the exploration of the floating island coming along?","TWN":"所以，天空島的探索情況如何？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"늘 그렇듯, 자네가 도착하기 전까지 상황이 그리 좋지 않았어.","JPN":"いつものように、おぬしが着くまで状況は芳しくなかった。","ENG":"As always, things weren't looking good before you arrived.","TWN":"老樣子，在你來之前狀況不太妙。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"탐험대의 수송선이 침식체의 공격을 받아, 보급품과 이동 수단을 잃어버렸거든.","JPN":"探検隊の輸送船が侵食体に襲われ、補給品と移動手段を失ってしまってな。","ENG":"The expedition's transport was attacked by C.O.s, leaving us without supplies or a way back down.","TWN":"探險隊的運輸艦遭受侵蝕體攻擊，補給品和交通工具全都沒了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"자네가 호출에 응하지 않으면, 어떻게 지상으로 돌아가야 하나, 고민하고 있던 참이었네.","JPN":"もしおぬしが呼び出しに応じてくれなかったら、どう地上に戻ればよいか悩んでいたところじゃった。","ENG":"I was wondering how we'd get back to the ground if you hadn't answered the call.","TWN":"要不是你有來，還真不知道該怎麼回地面呢。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"……늘 그렇듯, 최악의 상항이었군요.","JPN":"……いつものように、最悪の状況だったわけですね。","ENG":"...As always, the worst-case scenario.","TWN":"……老樣子，是最糟的情況嗎。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"하하! 예측할 수 없다는 점이야말로 탐험의 묘미 아니겠나?","JPN":"はは！　予測できないというところが探検の醍醐味じゃろう。","ENG":"Ha ha! But isn't that the thrill of exploration? Its unpredictability?","TWN":"哈哈！無法預測就是探險的樂趣不是嗎！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"걱정하지 말게. 황금향을 찾게 되면, 내 한몫 두둑이 챙겨줄 테니까.","JPN":"心配はいらん。黄金郷が見つかった暁には、おぬしにもたっぷり礼はしよう。","ENG":"Don't worry. Once I find the Golden Vale, I'll make sure you get your share.","TWN":"別擔心，等找到黃金城，我一定會給你一大筆分紅的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"됐으니까 사고 좀 그만 치십시오, 칸.","JPN":"そんなもの要りませんから、くれぐれも問題を起こさないようにしてくださいね、カン。","ENG":"Just stop causing trouble, Khan.","TWN":"不必了，你少惹點事就好，坎。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"10년째 같은 말씀을 하고 계시지 않습니까? 애송이 땐 속았지만, 이젠 안 속습니다.","JPN":"10年間同じことを言われ続ける身にもなってほしいものです。ガキの頃は騙されましたが、もう通じませんよ。","ENG":"You've been saying the same thing for ten years. I fell for it when I was a rookie, but not anymore.","TWN":"這句話你已經講了十年了。年輕的時候我還信，現在已經人間清醒。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"쯧쯔, 거 아직 팔팔하게 젊은 사람이 벌써 야망이 식었구만.","JPN":"ええい、まだ若いやつが早くも野望を捨ててどうする。","ENG":"Tsk, tsk. To think someone still young has already lost his fire.","TWN":"嘖嘖，年紀輕輕就這麼沒企圖心。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"요즘 젊은이들 사이에서는 인디애나 GAP인지 하는 놈팽이가 제법 유명한 모양이지만.","JPN":"最近の若者の間ではインディアナ-甲-とやらが名を馳せているようじゃが。","ENG":"I hear these days it's that rascal \\"Indiana G.A.P.\\" who's famous among the youth.","TWN":"現在年輕人好像都迷那個什麼印第安納GAP的傢伙吧？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"소싯적에 트레저 헌터라고 하면, 다들 이 몸을 가장 먼저 떠올리곤 했지.","JPN":"昔はトレジャーハンターといえばこのワシじゃった。","ENG":"But back in my day, when people thought of treasure hunters, they thought of me first.","TWN":"當年說到尋寶獵人，大家第一個想到的可是我呢！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"후우. 또 시작이군요.","JPN":"はあ、また始まりましたか。","ENG":"*Sigh* Here we go again.","TWN":"呼～ 又開始了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"허허, 자네도 기억하지 않나, 웨이드?","JPN":"ホホ、おぬしも覚えておるだろう？　ウェイド。","ENG":"Ha ha, you remember too, don't you, Wade?","TWN":"呵呵，韋德，你不記得了嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_SOF_JOHN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"<color=#ffd34c>마스터 칸</color>이라고 불렸던 시절, 이 몸의 위대한 여정을 말일세.","JPN":"<color=#ffd34c>マスター・カン</color>と呼ばれていた頃の、ワシの偉大なる冒険譚を。","ENG":"When they called me <color=#ffd34c>Master Khan</color>, and I was on my great journeys.","TWN":"當年大家都稱我為<color=#ffd34c>坎大師</color>！那可是我人生最輝煌的里程碑。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_SOF_JOHN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"그래. 이를 테면, 잃어버린 천 년의 도시. 에리두.","JPN":"そうじゃな、たとえば失われた千年の都市エリドゥ。","ENG":"Yes. For example, the lost millennial city of Eridu.","TWN":"比如說，那座失落千年的城市，埃里都！"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_SOF_JOHN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"그 도시를 찾기 위해, 물 한 모금조차 먹지 않고 로터스 사막 한 가운데를 헤맸었지.","JPN":"エリドゥを探して、ワシは水の一滴も飲まずロータス砂漠を彷徨った。","ENG":"I wandered the heart of the Lotus desert without a sip of water, just to find it.","TWN":"為了找到那座城市，我在洛德斯沙漠中連水都不敢喝，一直走到精疲力竭……"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_SOF_JOHN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"……그리고 결국에는 허탕이었죠.","JPN":"……そして結局は無駄足でしたね。","ENG":"...And in the end, it was all for nothing.","TWN":"……結果白忙一場。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"로터스 사막에서 탈진하여, 사경을 헤매던 당신을 구조한 게 저였지 않습니까?","JPN":"ロータス砂漠で脱水状態になり、死線を彷徨っていたあなたを救助したのは私じゃないですか。","ENG":"I was the one who saved you when you collapsed from exhaustion in that desert, wasn't I?","TWN":"是我在洛德斯沙漠裡把你從鬼門關拉回來的，還記得嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"그, 그랬었나……?","JPN":"そ、そうじゃったかな……？","ENG":"D-did you now...?","TWN":"是，是這樣嗎……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"허허, 이거 내가 헤매던 게 사막이 아니라, 사경이었구만.","JPN":"ホホ、ワシが彷徨っていたのは砂漠ではなく死線だったわけか。","ENG":"Ha ha! Then I suppose it wasn't the desert I was wandering, but at death's doorstep!","TWN":"哈哈，那我當時不是在沙漠徘徊，而是在鬼門關前嗎！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"그, 그렇지! 그럼, 이 이야기는 어떤가?","JPN":"そ、そうじゃ！　こ、この話もあるぞ。","ENG":"Ah! What about this tale?","TWN":"還，還有！那這個呢？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"프론트 베이의 검은 범람이 품고 있던 진귀한 보석, 검은 먹물 진주! 자네도 기억하지?","JPN":"フロントベイの黒い氾濫に隠されていた珍しい宝石、黒墨の真珠！　おぬしも覚えているじゃろう？","ENG":"The Black Pearl of the Black Flood in Front Bay. Remember that one?","TWN":"前灣的黑色洪災裡，有一顆傳說中的寶石，黑墨珍珠！你應該記得吧？"},"stage":{"bg":"HORIZON_02_A","bgm":"THEMA_SOF_JOHN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"그 보석을 손에 넣기 위해, 수많은 해적과 헌터들이 크라켄과 목숨을 건 사투를 벌였지.","JPN":"その宝石を手に入れるために、数多の海賊とハンターたちがクラーケンと命を賭けた死闘を繰り広げた。","ENG":"Pirates and hunters alike risked their lives against the Kraken to seize it.","TWN":"為了搶奪那顆寶石，無數海盜和獵人與克拉肯拼命廝殺！"},"stage":{"bg":"HORIZON_02_A","bgm":"THEMA_SOF_JOHN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"크으… 그때 잃었던 동료들을 생각하면, 아직도 눈물이 앞을 가리는구만.","JPN":"くぅ……あの時失った仲間のことを思い出すと、今も涙を堪えきれん。","ENG":"Kgh... Even now, I tear up when I think of the comrades I lost that day.","TWN":"嗚…想到當時犧牲的夥伴們，我現在都還眼眶泛淚呢……"},"stage":{"bg":"HORIZON_02_A","bgm":"THEMA_SOF_JOHN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"……뭐, 그랬었죠.","JPN":"……まあ、そうですね。","ENG":"...Yes, I remember.","TWN":"……沒錯。"},"stage":{"bg":"HORIZON_02_A","bgm":"THEMA_SOF_JOHN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"결과적으로는 그때도 허탕이었지만.","JPN":"結果として、それも無駄足でしたが。","ENG":"Though in the end, that expedition failed too.","TWN":"結果那次也是白忙一場。"},"stage":{"bg":"HORIZON_02_A","bgm":"THEMA_SOF_JOHN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"보물에 눈이 먼 선발대가 겁도 없이, 크라켄에게 돌진하다가 배가 난파되었으니까요.","JPN":"宝物に目がくらんだ先発隊が恐れも知らずクラーケンに突撃し、船が難破しましたからね。","ENG":"Blinded by greed, the advance party charged recklessly at the Kraken, and their ship was destroyed.","TWN":"先遣隊財迷心竅，結果原本要打克拉肯，結果船隻翻覆。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"당시 후속 토벌대로 투입되었던 신생 태스크포스…….","JPN":"当時、後続討伐隊として投入された新生タスクフォース……","ENG":"I was deployed in the follow-up TASKFORCE at the time...","TWN":"當時派去的新特遣勢力……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"코핀 컴퍼니가 토벌에 나서지 않았다면, 전부 죽은 목숨이었을 겁니다.","JPN":"コフィンカンパニーが討伐に出ていなければ、皆全滅していたでしょう。","ENG":"If Coffin Company hadn't joined the hunt, we'd all have been dead.","TWN":"如果不是後來科芬公司出手，大家早就死光了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"허허, 그때는 코핀 컴퍼니가 <color=#ffd34c>그런</color> 회사였을 줄은 상상도 못 했지만 말이야.","JPN":"ホホ、あの時はコフィンカンパニーが<color=#ffd34c>そういう</color>企業だとは思いもよらなかったが。","ENG":"Ha ha, back then I never imagined Coffin Company would become <color=#ffd34c>that kind</color> of corporation.","TWN":"哈哈，那時候還真沒想到，原來科芬公司是<color=#ffd34c>那種</color>公司。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"이거, 나도 모르게 최고 관리자 양반에게 신세를 지고 말았구만.","JPN":"知らぬうちに、最高管理者には世話になってしまったな。","ENG":"I suppose I owe a debt to the Supreme Administrator.","TWN":"我也不知不覺欠了最高管理者一份人情呢。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"신세가 아니라 민폐겠죠. 그 선발대를 이끌었던 선장이 바로 당신이었으니까요.","JPN":"世話になるというよりは迷惑をかけた、ですね。その先発隊を率いていた船長はあなたでしたから。","ENG":"A debt? More like a nuisance. You were the captain of that advance party.","TWN":"何止是欠人情？你根本是個大麻煩！當時先遣隊的船長就是你。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"그리고 맥주병이었던 당신의 목숨을 구해냈던 건, 그때도 저였죠.","JPN":"そしてカナヅチだったあなたを助けたのは、あの時も私でした。","ENG":"And I was the one who saved your drowning hide back then, too.","TWN":"是我救了你這個旱鴨子的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"그, 그랬었나……?","JPN":"そ、そうじゃったかな……？","ENG":"D-did you now...?","TWN":"是，是這樣嗎……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"프론트 베이 측에서 보냈던 배상 청구서, 아직 제가 보관하고 있습니다.","JPN":"フロントベイ側から送られてきた賠償請求書、まだ保管しています。","ENG":"I still have the compensation invoice Front Bay sent us.","TWN":"我還留著當時前灣寄來的賠償單呢。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"아, 아하핫…! 그랬었지! 나이가 드니까 영 기억력이 예전 같지 않구만!","JPN":"は、ははは……！　そうじゃった！　この歳になると記憶力が落ちてしまってな！","ENG":"Ahaha...! That's right! My memory's not what it used to be, I'm afraid.","TWN":"啊，啊哈哈……對對對！年紀大了，記性不太好！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"하지만 명심하게, 젊은이! 실패야 말로 탐험을 빛나게 하는 법이지!","JPN":"だが若者よ、肝に銘じておけ。失敗こそが探検を輝かせるのじゃ！","ENG":"But remember this, young man! Failure is what makes exploration shine!","TWN":"但記住了，年輕人！要是沒有失敗，就是只是平淡無奇的探險！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"그 실패들이 있었기에, 비로소 지금의 내가 이 곳에 있을 수 있는 것 아니겠나!","JPN":"あの失敗があったからこそ、今のワシがあるというものだ。","ENG":"Those failures are what shaped me into the man I am today.","TWN":"沒有那些失敗，就沒有今天的我！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"후후, 옛날이나 지금이나 그 허세는 여전하시군요.","JPN":"ふっ、昔も今も、その見栄っ張りだけはご立派ですね。","ENG":"Ha ha... Still as full of bluster as ever.","TWN":"呵呵～從以前到現在，你耍嘴皮的功夫一點都沒變呢。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"허세라니! 나는 언제나 진심이라고!","JPN":"見栄など張っておらん！　ワシはいつでも真剣じゃ！","ENG":"Bluster? I've always been sincere!","TWN":"耍嘴皮？我是說真的！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"뭐, 확실히 당신은 무모하고, 나잇값 못 하는 고집불통 노인네이긴 합니다만…….","JPN":"まあ、確かにあなたは無謀で、大人気のない頑固じじいですが……","ENG":"Well, sure. You're reckless, stubborn, and a damn old man who refuses to act his age...","TWN":"雖然你確實是個固執、不懂變通的老傢伙……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"적어도 그 탐험심은 인정할 만하죠.","JPN":"その探究心だけは認めざるを得ません。","ENG":"But at least your spirit of exploration is worth respecting.","TWN":"但你那股探險精神倒是值得尊敬。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"당신의 그 멍청한 탐험 덕분에 인류는 이면세계의 여러 비밀을 풀 수 있었으니까요.","JPN":"あなたの、そのバカげた探検のおかげで人類は裏世界のあらゆる謎を解くことができた。","ENG":"Thanks to your foolish expeditions, humanity has uncovered many secrets of the Counterside.","TWN":"因為你那愚蠢的探險，人類才能解開異界的諸多秘密。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"허허허… 이거 불안한데……?","JPN":"ホホホ……どうも落ち着かんな。","ENG":"Ha ha ha... Now I'm worried...","TWN":"呵呵呵…怎麼好像怪怪的…？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"왜 갑자기 평소에 안 하던 칭찬을 다 하고 그러나?","JPN":"どうしたんだ？　突然滅多にしない賞賛などしおって。","ENG":"Why the sudden praise, when you're usually not like this?","TWN":"你平常才不會這樣誇我？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"하지만 칸…….","JPN":"ですが、カン……","ENG":"But Khan...","TWN":"但是，坎……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"이제 그만 황금향은 포기하는 게 어떻겠습니까?","JPN":"そろそろ黄金郷のことは諦めたらどうですか？","ENG":"Don't you think it's time to give up on the Golden Vale?","TWN":"放棄黃金城好嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"관리국 설립 이래로, 당신은 트레저 헌터로서 수많은 공을 세웠습니다.","JPN":"管理局設立以来、あなたはトレジャーハンターとして多大な功績を上げた。","ENG":"Since the Administration was founded, you've earned great merit as a treasure hunter.","TWN":"自管理局成立以來，你作為尋寶獵人立下無數的功勞。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"물론, 그 중에 상당수는 사실보다 훨씬 과장된 것일지도 모르지만…….","JPN":"そのうちの大半は、実際より誇張された話かもしれませんが……","ENG":"Granted, many of those tales may be exaggerated...","TWN":"當然，其中可能有很大部分是經過誇大的……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"결과적으로 당신이 발굴해낸 아티팩트들이 세계의 재건에 큰 기여를 했다는 건, 그 누구도 부정할 수 없겠죠.","JPN":"結果的にあなたが発掘したアーティファクトが、世界の再建に大きく貢献したことは誰も否定できない。","ENG":"But no one can deny that the Artifacts you uncovered helped rebuild the world.","TWN":"但從結果上來看，你發掘出的人造神器對世界的重建做出巨大貢獻，這一點無人可以否認。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"그런 당신이 평생을 걸쳐, 황금향의 유산을 쫓아왔다는 건 저 역시 잘 알고 있어요.","JPN":"そんなあなたが一生をかけて黄金郷の遺産を追いかけてきたことは、私もよく分かっています。","ENG":"And I know full well that you've spent your entire life chasing the Golden Vale's Legacy.","TWN":"我也很清楚，你一生都在追尋黃金城的寶藏。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"그리고 개인적으로는 당신의 그 오랜 집념에 경의를 표합니다, 마스터 칸.","JPN":"そして個人的には、その飽くなき執念に敬意を払います。マスター・カン。","ENG":"On a personal note, I respect that lifelong conviction of yours, Master Khan.","TWN":"而我個人對你那長久以來的執著表示敬意，坎大師。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"웨이드, 자네……?","JPN":"ウェイド、おぬし……？","ENG":"Wade...?","TWN":"韋德，你……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"하지만 조금 더 자신의 정치적 입장을 자각하십시오.","JPN":"ですが、もう少しご自身の政治的立場を自覚してください。","ENG":"But you must also be mindful of your political standing.","TWN":"但是請你注意自己的政治立場。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"당신은 한낱 트레저 헌터가 아니라, 한 도시를 이끄는 시니어입니다.","JPN":"あなたはただのトレジャーハンターではなく、1つの都市を率いるシニアです。","ENG":"You're not just a treasure hunter. You're a Senior who leads a city.","TWN":"你不僅僅是一個普通的尋寶獵人，更是一位領導一座城市的Senior。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"다시 말해, 이 도시에서 가장 중요한 인물이라는 뜻이죠.","JPN":"つまり、この都市で最も重要な人物ということです。","ENG":"In other words, the most important figure in Campamento.","TWN":"換句話說，就是這座城市中最重要的人物。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"캄파멘토는 대반격 이후, 여섯 도시 중에서 가장 마지막에 수복된 도시입니다.","JPN":"カンパメントは大反撃後、6つの都市の中でも一番最後に修復された都市です。","ENG":"After the Counterattack, Campamento was the last of the six cities to be reclaimed.","TWN":"在大反擊後，坎帕門托是六座城市中最後一個被收復的。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"따라서 다른 직할 도시와는 달리 행정적 영향력과 인프라가 절대적으로 부족하죠.","JPN":"他の直轄都市とは違って、行政的な影響力もインフラも圧倒的に足りない。","ENG":"As such, unlike the other Administration Direct Control Cities, its administration and infrastructure are critically lacking.","TWN":"因此，與其他直轄市不同，這裡的行政影響力和基礎設施非常地不足。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"수많은 도시 재건을 성공한 샤레이드나 챔버와는 이제 격차를 따라잡을 수조차 없지 않습니까?","JPN":"都市再建に成功したシャレードやチェンバーとの格差は、もはや縮まる見込みはないに等しい。","ENG":"Compared to Charade or Chamber, which successfully rebuilt, the gap is impossible to close.","TWN":"與成功重建無數城市的查雷德和強巴相比，不覺得差距甚大嗎？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"자네가 이 도시를 사랑하는 건, 잘 알고 있다네, 웨이드.","JPN":"おぬしがこの都市を愛していることはワシもよく分かっておる、ウェイド。","ENG":"I know you love this city, Wade.","TWN":"我知道你愛這座城市，韋德。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"하지만 관리국의 여섯 직할 도시는 서로 경쟁하는 게 아니야. 저마다 역할이 있을 뿐이지.","JPN":"しかし、管理局の6つの直轄都市は競争関係ではない。それぞれの役割が違うのじゃ。","ENG":"But the six Administration Direct Control Cities aren't meant to compete. Each has its own role.","TWN":"但是管理局的六個直轄市並不是互相競爭的，它們各自有自己的角色。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"자네도 알다사피, 캄파멘토는 탐험가들의 도시.","JPN":"おぬしも知っている通り、カンパメントは探検家の都市。","ENG":"As you know, Campamento is the city of explorers.","TWN":"你也知道，坎帕門托是探險者之城。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"이터니움과 아티팩트를 쫓아, 수많은 태스크포스와 트레저 헌터들이 이곳에 모인다네.","JPN":"エタニウムとアーティファクトを追うタスクフォースとトレジャーハンターが皆ここに集まって来る。","ENG":"Chasing Eternium and Artifacts, countless TASKFORCEs and treasure hunters gather here.","TWN":"眾多特遣勢力和尋寶獵人聚集於此，追尋永恆之晶和人造神器。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"따라서 이 도시는 침식지대에 관한 탐험 및 연구 그리고 관광이 활발이 이루어지고 있어.","JPN":"この都市で侵食地帯への探検、研究、観光が盛んなのはそのためじゃ。","ENG":"So the city thrives on exploration, research, and tourism of the Corrupted Areas.","TWN":"因此，這座城市在侵蝕地帶的探險、研究和旅遊方面都非常活躍。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"이런 상황에서 관리국이 필요 이상으로 간섭하려 들면, 오히려 도시가 위축할 걸세.","JPN":"こんな状況で管理局が必要以上に干渉すれば、逆に都市は沈滞してしまうじゃろう。","ENG":"If the Administration meddles too much here, the city will only wither.","TWN":"在這種情況下，如果管理局過度干涉，反而會讓城市萎縮。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"캄파멘토가 모두에게 개방된 자유 도시라는 점은 알고 있습니다.","JPN":"カンパメントが万民に開放されている自由都市であることは分かります。","ENG":"I understand Campamento is an open, free city.","TWN":"我知道坎帕門托是對所有人開放的自由城市。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"하지만 그 반대급부로 수많은 문제가 방치되고 있다는 것도 사실이죠.","JPN":"しかしそれゆえに多くの問題が放置されていることも事実です。","ENG":"But that openness leaves many problems neglected.","TWN":"但許多問題也因此被擱置不管，這也是事實。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"버려진 침식지대와 관리 거부 구역, 종교 분쟁… 그로 인해, 발생하는 치안 문제…….","JPN":"放棄された侵食地帯、管理拒否区域、宗教紛争……それに伴う治安の問題……","ENG":"Abandoned Corrupted Areas, Anti-Administration Zones, religious conflicts... All of which strain public safety...","TWN":"被遺棄的侵蝕地帶和管理拒絕區域，宗教紛爭……因此引發的治安問題……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"기억하십니까, 시니어 칸?","JPN":"覚えていますか？　シニア・カン。","ENG":"Do you remember, Senior Khan?","TWN":"你還記得嗎，Senior？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"학회의 대규모 숙청과 그로 인해 파생된 신흥 종교 집단, <color=#ffd34c>얄다바오트의 자녀들</color>…….","JPN":"学会の大規模粛清と、そこから派生した新興宗教集団、<color=#ffd34c>ヤルダバオトの子供</color>……","ENG":"The Society's massive purge, and the rise of the new cult called the <color=#ffd34c>Children of Yaldabaoth</color>...","TWN":"學會的大規模肅清，以及由此衍生的新興宗教團體，<color=#ffd34c>亞達巴沃的子女們</color>……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"다른 직할 도시들은 그들의 거점이 캄파멘토 어딘가에 있다고 주장하고 있습니다.","JPN":"他の直轄都市は、彼らの拠点がここ、カンパメントのどこかにあると主張しています。","ENG":"The other Administration Direct Control Cities claim their base of operations is hidden somewhere in Campamento.","TWN":"其他直轄市聲稱他們的據點位於坎帕門托的某個地方。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"이 따위, 근거 없는 중상모략을 지켜만 보실 생각입니까?","JPN":"こんな根拠のない誹謗中傷を、黙って見過ごすつもりですか？","ENG":"Are you just going to sit back and tolerate such baseless slander?","TWN":"對於他們的誹謗你打算坐視不管嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"지금 이 도시에 필요한 건, 탐험이 아니라 안정입니다.","JPN":"今この都市に必要なのは、探検ではなく安定です。","ENG":"What this city needs is not exploration, but stability.","TWN":"現在這座城市需要的不是探險，而是安定。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"적어도 당신께서는 캄파멘토 관리국의 중심을 지켜 주셔야만 합니다.","JPN":"少なくともあなたは、カンパメント管理局の中心を守らなければなりません。","ENG":"At the very least, you must hold the center of the Campamento Administration.","TWN":"至少你必須要守護好坎帕門托管理局的核心。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"당신의 정치적 입지를 이용한다면, 충분히 가능한 일일 텐데요?","JPN":"あなたの政治的な立場を利用すれば、十分可能なはずです。","ENG":"If you leverage your political standing, it can be done.","TWN":"如果利用你的政治地位，這完全可能吧？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"허허. 정치라…….","JPN":"ホホ。政治、か……","ENG":"Ha ha. Politics, you say...","TWN":"呵呵，政治地位嗎……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"그런 생각을 하고 있을 줄이야. 자네도 제법 나이를 먹었구만.","JPN":"そんなことを考えておったとは。おぬしも歳を取ったのう。","ENG":"To think you'd be saying that. You really have aged, Wade.","TWN":"沒想到你會有這樣的想法，看來你也老了不少。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"하지만 들어보게, 웨이드.","JPN":"聞いてくれ、ウェイド。","ENG":"But listen, Wade.","TWN":"但是你聽我說，韋德。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"사람은 자신의 본성대로 살아야 하는 법일세. 타고난 운명은 거스를 수 없어.","JPN":"人間は本性に従って生きるべきじゃ。生まれ持った運命には逆らえん。","ENG":"A man must live true to his nature. Fate cannot be defied.","TWN":"人應該按照自己的本性生活，與生俱來的命運是無法違背的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"이 나이를 먹도록 나에겐 아내도 자식도 없지. 내 사주에는 역마살이 끼어 있거든.","JPN":"ワシはこの歳で妻も子もおらん。放浪癖とでも言うべきか、まあ、流浪の運命の下にいてのう。","ENG":"All these years, I've had no wife, no children. My fortune has always carried the mark of a wanderer.","TWN":"我到了這個年紀，依然沒有妻子，是因為我命中註定要漂泊不定。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"지금껏 바람을 벗 삼아, 구름과 함께 세계 이곳저곳을 떠돌아다녔네.","JPN":"風を友とし、雲と共に世界各地を駆け巡った。","ENG":"Thus I've roamed the world with the wind as my companion and the clouds at my side.","TWN":"至今為止，我一直以風為伴，和雲一起環遊世界。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"그리고 관리국은 이런 <color=#ffd34c>나</color>를 이 도시의 시니어로 선택했어.","JPN":"そして管理局はこんな<color=#ffd34c>ワシ</color>を、この都市のシニアに選んだ。","ENG":"And yet the Administration chose someone like <color=#ffd34c>me</color> as this city's Senior.","TWN":"而管理局選擇這樣的<color=#ffd34c>我</color>來擔任這座城市的Senior。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"……그 <color=#ffd34c>관리국</color>이 말일세.","JPN":"……あの<color=#ffd34c>管理局</color>が、だ。","ENG":"...Yes, the <color=#ffd34c>Administration</color> itself.","TWN":"……是<color=#ffd34c>管理局</color>的意思。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L23_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"공인 카운터인 자네라면, 이게 무슨 뜻인지 충분히 짐작할 수 있을 텐데?","JPN":"公認カウンターであるおぬしなら、この意味が分かるじゃろう？","ENG":"As an Official Counter, you can understand what that means, can't you?","TWN":"身為公認制裁者的你，應該能充分猜到這是什麼意思吧？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"비록 비루한 재능이지만, 탐험에 평생을 바치고 탐험가로서 여기까지 올라온 몸일세.","JPN":"しがない才能だが、生涯を探検に捧げ、探検家としてここまで登りつめた身じゃ。","ENG":"My talents may be paltry, but I've devoted my life to exploration and risen this far as an explorer.","TWN":"雖然我的才能有限，但我的一生都在探險，我是用探險家的身分一路走到今天的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"그 탐험심을 빼앗는 건, 설령 최고 관리자 양반이 복귀한다고 해도 불가능해.","JPN":"たとえ最高管理者が復帰するとしても、その探究心は奪えはせん。","ENG":"Even if the Administrator himself returned, he could not strip me of that spirit.","TWN":"即使最高管理者回歸，也無法奪走我的探險精神。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"내가 원하든 원치 않든, 내가 이 자리에서 하고자 하는 일이 곧 관리국의 뜻이네.","JPN":"ワシが望もうが望むまいが、ワシがここでやろうとすることこそが管理局の意思じゃ。","ENG":"Whether I want it or not, what I seek here is aligned with the Administration's will.","TWN":"無論我是否願意，我在這個位置上要做的事，也就是管理局想做的事。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"그러니까 황금향의 유산을 찾는 건, 분명 이 세계에 필요한 일일 거야.","JPN":"となれば黄金郷の遺産を探すことは、きっとこの世界に必要なことなのじゃろう。","ENG":"Which means finding the Golden Vale's Legacy is indeed what this world needs.","TWN":"所以尋找黃金城的寶藏，肯定是這個世界所需要的事情。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"설령, 황금향이 존재하더라도…….","JPN":"黄金郷が本当に存在するとしても……","ENG":"Even if the Golden Vale truly exists...","TWN":"就算黃金城真的存在……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"어디 있는지도 모르는 황금의 도시를 위해, 지금의 도시를 방관하는 꼴입니다.","JPN":"どこにあるのかも分からない黄金の都市のために、今の都市を傍観することになります。","ENG":"You're neglecting the city you have now for a golden city that may not even exist.","TWN":"為了那座不知身在何處的黃金之城，而對現在的城市置之不理。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"만약 당신의 신변에 문제가 생긴다면, 캄파멘토 관리국은 혼란에 빠지게 되겠죠.","JPN":"もしあなたの身辺に何かあれば、カンパメント管理局は混乱に陥るでしょう。","ENG":"If anything happens to you, the Campamento Administration will fall into chaos.","TWN":"如果你的安全出現問題，坎帕門托管理局將會陷入混亂。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"지금까지는 제가 있어 운이 좋았지만, 앞으로도 매번 그러리라는 보장은 없습니다.","JPN":"今までは私がいて事なきを得ましたが、今後もそうだという保証はありません。","ENG":"You've been fortunate to have me by your side thus far, but that luck won't last forever.","TWN":"到目前為止，你很幸運有我在身邊，但不能保證以後每次都會如此。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"다시 한번… 미래에 이 도시를 터전으로 살아가게 될 아이들을 다시 한번 생각해 주십시오.","JPN":"どうか……将来、この都市で行きていく子供たちのことを思ってください。","ENG":"Please... Think once more of the children who will call this city their home in the future.","TWN":"拜託……請你再一次為那些在這座城市生活的孩子們考慮一下。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"아이들이라…….","JPN":"子供たちか……","ENG":"Children, eh...?","TWN":"孩子們……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"……자네의 말은 옳아.","JPN":"……おぬしの言っていることはもっともじゃ。","ENG":"...You're right.","TWN":"……你說得對。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"하지만 이 땅에서 관리 실패를 직접 목격했던 나에게는 사명이 있네.","JPN":"しかしこの地で管理失敗を直に目撃したワシには使命がある。","ENG":"But I carry a mission because I witnessed the Administration Failure with my own eyes.","TWN":"但是對於在這片土地上親眼目睹管理失敗的我來說有一個使命。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"미래의 아이들을 위해, 결코 그런 사태를 반복해서는 안 된다는 사명이지.","JPN":"未来の子供たちのために、決してあのような事態を繰り返してはならないというな。","ENG":"A mission to ensure such a disaster never happens again, for the sake of the children's future.","TWN":"為了將來的孩子們，絕不能讓那種事態重演，這就是我的使命。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"그렇지만, 칸! 황금향은 그저 전설일 뿐이지 않습니까……!","JPN":"ですが、カン！　黄金郷はただの伝説にすぎません……！","ENG":"But Khan! The Golden Vale is just a legend...!","TWN":"可是，坎！黃金城只是一個傳說……！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L50_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"그렇다네, 그저 전설일 뿐이지.","JPN":"ああ、ただの伝説にすぎん話じゃ。","ENG":"Yes, just a legend.","TWN":"沒錯，只不過是個傳說而已。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"노스트라다무스의 지구 종말론, 마야족의 달력설, 시빌라의 예언서…….","JPN":"ノストラダムスの人類滅亡論、マヤ族の暦にまつわる話、シビュラの書……","ENG":"Nostradamus' doomsday prophecies, the Mayan calendar, the Sibyl's oracles...","TWN":"諾斯特拉達穆斯的地球末日論、馬雅曆法的末日說、西比拉的預言書……  "},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"세계 종말에 관한 전설은 어느 시대에나 존재하고. 또 언젠가 부질없이 사라지곤 해.","JPN":"世界終末に関する伝説はどの時代にも存在し、時とともに虚しく消えていく。","ENG":"Legends of the end exist in every era, and vanish just as easily.","TWN":"關於世界末日的預言，在任何時代都曾存在，最後也都悄然消逝。  "},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"내가 쫓고 있는 황금향의 전설이라고, 결코 그보다 낫다고는 말할 생각은 없어.","JPN":"黄金郷の伝説も、ワシが追いかけているからといって、それらの予言よりましだなどと言うつもりはない。","ENG":"I make no claim that the legend I chase is any different, or any better.","TWN":"我從未覺得我所追尋的黃金城傳說勝過那些傳說。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"나는 힘을 쓰는 무인이 아닐세. 학문을 추구하는 문인은 더더욱 아니지.","JPN":"ワシは力を行使する武人ではない。ましてや、学問を追求する文人でもない。","ENG":"I'm no warrior of strength, nor am I a scholar of letters.","TWN":"我不是使用武力的武人，更不是追求學問的文人。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"혹자는 내 사명이 지나치게 허황되고 터무니없는 것이라고 손가락질할지도 몰라.","JPN":"誰かはワシの使命が非現実的で大袈裟すぎると批判するかもしれん。","ENG":"Some may call my mission absurd, far-fetched, and laugh at me for it.","TWN":"有人可能會指責我的使命過於天馬行空。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"그럼에도 나는 황금향의 존재를 포기할 생각이 없네.","JPN":"それでもワシは黄金郷の存在を諦めるつもりはないぞ。","ENG":"Even so, I will not give up on the Golden Vale's existence.","TWN":"可就算是這樣，我也不打算放棄黃金城。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"탐험가로서의 내 직관이, 내 삶이 그리고 평생을 걸쳐 모아온 역사적 단서들이 그곳의 실존을 외치고 있어.","JPN":"探検家としてのワシの勘が、ワシの人生が、そして生涯をかけて集めてきた歴史的な手がかりが、あれは実在すると告げているんじゃ。","ENG":"My instincts as an explorer, my life, and the clues I've gathered cry out that it is real.","TWN":"作為探險家的直覺，我的生命，以及我一生中收集的歷史線索都在呼喊著那個地方。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"따라서 내 뜻에는 변함이 없네.","JPN":"ワシの意思は変わらん。","ENG":"So my resolve will not waver.","TWN":"所以，我的想法不會改變。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"훗날 역사의 평가가 지도자로서 내 선택이 틀렸다며 비웃더라도 말이지.","JPN":"後日、指導者としてあるまじき判断だったと嘲笑われることになったとしてもな。","ENG":"Even if history one day mocks me as a leader who chose wrongly.","TWN":"就算未來的歷史評價我作為領導者的選擇是錯誤的，並嘲笑我。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"늘 그렇듯, 당신은 무모하고 나잇값 못하는 망할 노인네로군요, 칸.","JPN":"いつものように、あなたは無謀で大人気ないじじいですね、カン。","ENG":"As always, you're a reckless, damn old man, Khan.","TWN":"還是一樣呢。你這個做事不經大腦的老傢伙。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"다만, 아무리 어리석을지라도 누군가가 평생을 바친 집념을 어떻게 비웃겠습니까?","JPN":"ですが、どんなに愚かだとしても、誰かが一生を捧げた執念が笑われることはありません。","ENG":"But no matter how foolish, how can I scorn a man's conviction when he's devoted his whole life to it?","TWN":"但是，無論多麼愚蠢，怎麼能嘲笑一個人畢生的心願呢？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"허허, 그렇게 말해주니 고맙구만.","JPN":"ホホ、そう言ってくれるか。","ENG":"Ha ha, thank you for saying that.","TWN":"呵呵，謝謝你這麼說。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"역사는 몰라도, 적어도 자네만큼은 날 좋게 평가해 주는군.","JPN":"歴史はともかく、おぬしだけはワシを評価してくれるんじゃな。","ENG":"History may not, but at least you think well of me, Wade.","TWN":"即使不知道歷史會怎麼說，至少你對我的評價還不錯。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"후우…….","JPN":"ふう……","ENG":"*Sigh...*","TWN":"呼……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"어차피 제가 뭐라하든, 당신은 당신의 사명을 위해 목숨을 걸겠죠.","JPN":"私が何を言おうが、どうせあなたはご自身の使命のために命をかけるでしょう。","ENG":"No matter what I say, you'll risk your life for your mission.","TWN":"反正無論我說什麼，你都會為了你的使命付出一切吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"그리고 저는 이 도시의 공인 카운터. 캄파멘토를 지키는 난공불락의 방패.","JPN":"そして私はこの都市の公認カウンター。カンパメントを守る難攻不落の盾。","ENG":"And I am an Official Counter. The shield that defends Campamento.","TWN":"而我是這座城市的公認制裁者，是守護坎帕門托堅不可摧的盾牌。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"……좋습니다.","JPN":"……いいでしょう。","ENG":"...Very well.","TWN":"……好吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L25_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"당신이 사명을 위해 목숨을 건다면, 저도 사명을 위해 목숨을 걸겠습니다.","JPN":"あなたが使命のために命をかけるというなら、私も使命のために命をかけます。","ENG":"If you'll risk your life for your mission, then I'll risk mine for mine.","TWN":"如果你願意為使命獻出生命，我也會為使命獻出生命。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"어쨌든 당신에는 빚이 있으니까요.","JPN":"あなたには借りがありますからね。","ENG":"After all, I owe you a debt.","TWN":"不管怎樣，你欠我一個人情。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};